"use client";

import { useState } from "react";
import { supabase } from "@/utils/supabase/client";
import { Mail, CheckCircle, ArrowRight } from "lucide-react";
import Link from 'next/link';

export default function Login() {
  const [email, setEmail] = useState("");
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState("");

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    const { error } = await supabase.auth.signInWithOtp({
      email,
      options: {
        emailRedirectTo: `${window.location.origin}/auth/callback`,
      },
    });

    if (error) {
      setMessage("에러: " + error.message);
    } else {
      setMessage("이메일로 로그인 링크를 보냈습니다! 메일함을 확인해주세요.");
    }
    setLoading(false);
  };

  return (
    <div className="min-h-screen bg-navy flex items-center justify-center p-4">
      <div className="bg-white/10 p-8 rounded-2xl border border-white/20 backdrop-blur-md w-full max-w-md shadow-2xl relative overflow-hidden">
        {/* Decorative elements */}
        <div className="absolute top-0 right-0 w-32 h-32 bg-sky-500/20 rounded-full blur-3xl -mr-10 -mt-10"></div>
        <div className="absolute bottom-0 left-0 w-32 h-32 bg-blue-500/20 rounded-full blur-3xl -ml-10 -mb-10"></div>

        <div className="relative z-10">
          <Link href="/" className="inline-flex items-center text-gray-400 hover:text-white mb-6 text-sm transition-colors">
            <ArrowRight className="w-4 h-4 mr-1 rotate-180" /> 홈으로 돌아가기
          </Link>

          <h1 className="text-3xl font-bold text-sky-400 text-center mb-2">
            주식콕 로그인
          </h1>
          <p className="text-gray-300 text-center mb-8">
            복잡한 주식 정보, 간편하게 시작하세요.
          </p>

          {message ? (
            <div className="bg-green-500/20 border border-green-500/50 p-4 rounded-lg flex items-center gap-3 text-green-200 animate-fade-in">
              <CheckCircle className="w-5 h-5 flex-shrink-0 text-green-400" />
              <p className="font-medium">{message}</p>
            </div>
          ) : (
            <form onSubmit={handleLogin} className="space-y-5">
              <div>
                <label className="block text-sm font-medium text-gray-300 mb-2">
                  이메일 주소
                </label>
                <div className="relative group">
                  <Mail className="absolute left-3 top-3.5 w-5 h-5 text-gray-400 group-focus-within:text-skyblue transition-colors" />
                  <input
                    type="email"
                    required
                    value={email}
                    onChange={(e) => setEmail(e.target.value)}
                    className="w-full pl-10 pr-4 py-3 bg-black/30 border border-white/10 rounded-xl focus:outline-none focus:ring-2 focus:ring-skyblue text-white placeholder-gray-500 transition-all font-medium"
                    placeholder="name@example.com"
                  />
                </div>
              </div>

              <button
                type="submit"
                disabled={loading}
                className="w-full py-3.5 bg-skyblue hover:bg-blue-500 text-white font-bold rounded-xl transition-all shadow-lg shadow-blue-500/30 disabled:opacity-50 disabled:cursor-not-allowed transform hover:scale-[1.02] active:scale-[0.98]"
              >
                {loading ? (
                  <span className="flex items-center justify-center gap-2">
                    <span className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin"></span>
                    전송 중...
                  </span>
                ) : "매직 링크 보내기"}
              </button>
              <div className="text-center space-y-2">
                <p className="text-xs text-gray-400/80">
                  비밀번호 없이 이메일로 안전하게 로그인합니다.
                </p>
              </div>
            </form>
          )}
        </div>
      </div>
    </div>
  );
}
